import{c as e,Q as o,j as a,m as n}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"指令、函数与谓词系统","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/21-指令函数与谓词系统.md","filePath":"minecraftLearning/21-指令函数与谓词系统.md","lastUpdated":1781676649000}'),s={name:"minecraftLearning/21-指令函数与谓词系统.md"};function d(c,t,r,i,p,l){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="指令、函数与谓词系统" tabindex="-1">指令、函数与谓词系统 <a class="header-anchor" href="#指令、函数与谓词系统" aria-label="Permalink to &quot;指令、函数与谓词系统&quot;">​</a></h1><p>前面二十篇讲的都是&quot;世界是什么、怎么存、怎么跑&quot;——方块、实体、区块、存档、注册表。但有一层我们一直绕着走:<strong>普通人不写一行 Java,怎么往这套数据模型上加逻辑?</strong> 答案就是指令 + 数据包。这是 Minecraft 的&quot;脚本/逻辑层&quot;,建在前面所有数据模型之上,也是地图作者、服务器、模组之外最大的一块可玩性来源。</p><blockquote><p>一句话先记住:<strong>指令系统不是&quot;作弊码集合&quot;,而是一套对世界数据模型的结构化读写 API;Brigadier 把每条命令变成一棵带类型的参数树,mcfunction 把命令打包成脚本,谓词/战利品表把&quot;判定&quot;和&quot;产出&quot;抽成可复用的 JSON。整层不碰 Java,纯数据驱动。</strong></p></blockquote><hr><h2 id="一、brigadier-命令是一棵树-不是一个字符串" tabindex="-1">一、Brigadier:命令是一棵树,不是一个字符串 <a class="header-anchor" href="#一、brigadier-命令是一棵树-不是一个字符串" aria-label="Permalink to &quot;一、Brigadier:命令是一棵树,不是一个字符串&quot;">​</a></h2><p>新手以为 <code>/give @p diamond 64</code> 是&quot;解析一个字符串&quot;。错。从 1.13 起,Minecraft 的命令引擎是独立库 <strong>Brigadier</strong>,它把所有命令建模成<strong>一棵带类型参数的节点树</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>根</span></span>
<span class="line"><span>├── give</span></span>
<span class="line"><span>│    └── &lt;targets: 实体选择器&gt;</span></span>
<span class="line"><span>│         └── &lt;item: 物品参数&gt;</span></span>
<span class="line"><span>│              └── &lt;count: 整数 0..&gt;   ← 可选,缺省走上一层的 executes</span></span>
<span class="line"><span>├── tp / teleport</span></span>
<span class="line"><span>│    └── ...</span></span>
<span class="line"><span>└── execute</span></span>
<span class="line"><span>     ├── as &lt;targets&gt; → (回到 execute 子节点)</span></span>
<span class="line"><span>     ├── at &lt;targets&gt; → ...</span></span>
<span class="line"><span>     └── run → (整棵命令树作为子命令)</span></span></code></pre></div><p>每个节点有三种:<strong>literal</strong>(字面量,如 <code>give</code>)、<strong>argument</strong>(带类型解析器,如 <code>targets</code>/<code>item</code>/<code>count</code>)、以及 redirect(指向别的子树,<code>execute</code> 的递归就靠它)。这套设计带来几个直接好处:</p><table tabindex="0"><thead><tr><th>能力</th><th>怎么来的</th></tr></thead><tbody><tr><td><strong>类型化解析</strong></td><td>每个 argument 节点自带解析器,<code>count</code> 解析成 int 而不是字符串,越界当场报错并指出列位置</td></tr><tr><td><strong>tab 补全</strong></td><td>节点知道自己接受什么,补全就是&quot;问当前节点:你的下一步候选有哪些&quot;</td></tr><tr><td><strong>权限校验</strong></td><td>每个节点挂一个 <code>requires</code> 谓词(如 OP 等级 ≥ 2),不满足时这棵子树对你<strong>不可见</strong>——既是鉴权也是补全过滤</td></tr><tr><td><strong>错误定位</strong></td><td>解析在树上逐节点推进,失败点就是光标该停的地方</td></tr></tbody></table><p><strong>反直觉点:命令树会同步给客户端。</strong> 你按 tab 能即时补全、输错立刻变红,不是客户端瞎猜,而是<strong>服务端在握手后把整棵命令树打包发给客户端</strong>(呼应第 13 篇:这走 play 阶段的一个包)。客户端用这棵树做本地补全和高亮,真正执行时再发回服务端。所以装了命令的服务端,客户端补全会随之变化;反作弊也据此知道你&quot;理论上能打哪些命令&quot;。</p><hr><h2 id="二、选择器-对实体表的一次带过滤查询" tabindex="-1">二、选择器:对实体表的一次带过滤查询 <a class="header-anchor" href="#二、选择器-对实体表的一次带过滤查询" aria-label="Permalink to &quot;二、选择器:对实体表的一次带过滤查询&quot;">​</a></h2><p><code>@e</code>、<code>@a</code>、<code>@p</code>、<code>@s</code>、<code>@r</code> 不是&quot;魔法变量&quot;,本质是<strong>对世界实体集合的一次查询</strong>,返回一个目标列表:</p><table tabindex="0"><thead><tr><th>选择器</th><th>含义</th><th>默认排序/数量</th></tr></thead><tbody><tr><td><code>@s</code></td><td>命令执行者自己</td><td>1 个,最便宜</td></tr><tr><td><code>@p</code></td><td>最近的玩家</td><td>按距离,1 个</td></tr><tr><td><code>@r</code></td><td>随机玩家</td><td>随机 1 个</td></tr><tr><td><code>@a</code></td><td>所有玩家</td><td>不限</td></tr><tr><td><code>@e</code></td><td>所有实体</td><td>不限,<strong>最贵</strong></td></tr></tbody></table><p>真正的威力在<strong>参数过滤</strong>,它就是查询的 where 子句:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@e[type=zombie, distance=..16, nbt={IsBaby:0b}, limit=5, sort=nearest]</span></span>
<span class="line"><span>@a[gamemode=survival, scores={kills=10..}, tag=red]</span></span>
<span class="line"><span>@e[type=item, predicate=mypack:is_diamond]</span></span></code></pre></div><ul><li><code>type</code> / <code>distance</code> / <code>gamemode</code> / <code>scores</code> / <code>tag</code>:常见维度过滤。</li><li><code>nbt={...}</code>:直接匹配实体的 NBT 子树(呼应第 8 篇:实体就是一棵 NBT)。</li><li><strong>物品/组件匹配</strong>:1.20.5 物品迁到数据组件后(呼应第 17 篇),很多匹配从&quot;翻 NBT tag&quot;变成&quot;匹配组件&quot;,<code>predicate</code> 和物品判定更精确、更强类型。</li></ul><p>性能上有个该记的取舍:<strong><code>@e</code> 不带 <code>type</code>/<code>limit</code> 是会扫全实体表的</strong>,大地图里滥用 <code>@e[...]</code> 是 mcfunction 卡顿的常见来源。能用 <code>@s</code> 就不用 <code>@p</code>,能 <code>type=</code> 限定就别裸 <code>@e</code>。</p><h3 id="execute-把-上下文-拆成可组合的子命令" tabindex="-1">execute:把&quot;上下文&quot;拆成可组合的子命令 <a class="header-anchor" href="#execute-把-上下文-拆成可组合的子命令" aria-label="Permalink to &quot;execute:把&quot;上下文&quot;拆成可组合的子命令&quot;">​</a></h3><p><code>execute</code> 是整个命令系统的关节,它不直接做事,而是<strong>改变后续命令的执行上下文</strong>,再 <code>run</code> 一条真正的命令:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>execute as @a[tag=player] at @s if block ~ ~-1 ~ minecraft:gold_block run give @s diamond</span></span>
<span class="line"><span>        └ 把执行者换成每个玩家  └ 把坐标锚到他脚下  └ 条件:脚下是金块  └ 满足才执行</span></span></code></pre></div><ul><li><code>as</code>:换<strong>执行者</strong>(<code>@s</code> 指向谁)。</li><li><code>at</code> / <code>positioned</code> / <code>rotated</code>:换<strong>坐标/朝向锚点</strong>(<code>~ ~ ~</code> 相对谁)。</li><li><code>if</code> / <code>unless</code>:<strong>条件分支</strong>,接 <code>block</code>/<code>entity</code>/<code>score</code>/<code>predicate</code> 等。</li><li><code>store</code>:把结果<strong>写回</strong>计分板或 NBT,实现&quot;取值&quot;。</li></ul><p><code>as @a ... run</code> 会对每个匹配目标<strong>各跑一遍</strong>——这就是&quot;对一群玩家批量操作&quot;的标准写法,也是为什么一条 <code>execute</code> 能展开成上千次执行、需要小心成本。</p><hr><h2 id="三、mcfunction-把命令打包成脚本-并挂进-tick-循环" tabindex="-1">三、mcfunction:把命令打包成脚本,并挂进 tick 循环 <a class="header-anchor" href="#三、mcfunction-把命令打包成脚本-并挂进-tick-循环" aria-label="Permalink to &quot;三、mcfunction:把命令打包成脚本,并挂进 tick 循环&quot;">​</a></h2><p>单条命令是交互式的。把一堆命令按行写进一个 <code>.mcfunction</code> 文件,就成了<strong>函数</strong>——一个最朴素的脚本:逐行顺序执行,无变量、无返回值(早期)、靠计分板和 NBT 当&quot;内存&quot;。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># mypack:tick_logic  (data/mypack/functions/tick_logic.mcfunction)</span></span>
<span class="line"><span>execute as @a at @s if block ~ ~-1 ~ minecraft:magma_block run damage @s 1 minecraft:in_fire</span></span>
<span class="line"><span>scoreboard players add @a timer 1</span></span>
<span class="line"><span>execute if score #global timer matches 200 run function mypack:every_10s</span></span></code></pre></div><p>关键不是语法,而是<strong>怎么让它自动跑</strong>。这就用到<strong>函数标签</strong>(呼应第 11 篇的 Tag 机制):</p><table tabindex="0"><thead><tr><th>函数标签</th><th>触发时机</th></tr></thead><tbody><tr><td><code>#minecraft:load</code></td><td>世界/数据包加载或 <code>/reload</code> 时跑一次——初始化计分板、常量</td></tr><tr><td><code>#minecraft:tick</code></td><td><strong>每个游戏 tick 跑一次</strong>——把你的逻辑钉进 20 TPS 主循环</td></tr></tbody></table><p>把你的函数加进 <code>#minecraft:tick</code> 标签,它就成了世界 tick 的一部分(呼应第 4 篇:和方块更新、实体 tick 一起,每 50ms 跑一轮)。<strong>这是整个数据包能&quot;活起来&quot;的开关</strong>——没有它,函数只能被手动或被别的命令调用。</p><p>代价也很直接:<strong><code>#minecraft:tick</code> 里的东西每秒跑 20 次</strong>,一条扫全图的 <code>@e</code> 选择器放这儿就是稳定的性能黑洞。成熟数据包都会用计分板做&quot;每 N tick 才跑一次&quot;的节流,把重活从每 tick 摊开。</p><hr><h2 id="四、谓词、战利品表、进度、配方-把-判定-和-产出-抽成数据" tabindex="-1">四、谓词、战利品表、进度、配方:把&quot;判定&quot;和&quot;产出&quot;抽成数据 <a class="header-anchor" href="#四、谓词、战利品表、进度、配方-把-判定-和-产出-抽成数据" aria-label="Permalink to &quot;四、谓词、战利品表、进度、配方:把&quot;判定&quot;和&quot;产出&quot;抽成数据&quot;">​</a></h2><p>命令是&quot;动作&quot;,但 Minecraft 还把另外两类东西抽成了<strong>纯 JSON、可复用</strong>的定义,这是数据驱动的精髓:</p><table tabindex="0"><thead><tr><th>定义类型</th><th>回答的问题</th><th>谁来用</th></tr></thead><tbody><tr><td><strong>谓词 predicate</strong></td><td>&quot;当前情况满足条件吗?&quot;(实体类型、位置、天气、手持物、随机数…)</td><td><code>execute if predicate</code>、战利品条件、选择器 <code>predicate=</code></td></tr><tr><td><strong>战利品表 loot table</strong></td><td>&quot;该掉/给出哪些物品?&quot;(带权重、函数、条件)</td><td>箱子、怪物掉落、钓鱼、<code>/loot</code>、方块破坏</td></tr><tr><td><strong>进度 advancement</strong></td><td>&quot;玩家达成了什么?触发什么奖励?&quot;</td><td>成就树、隐藏触发器当事件钩子</td></tr><tr><td><strong>配方 recipe</strong></td><td>&quot;什么输入合成什么输出?&quot;</td><td>工作台/熔炉/锻造台匹配</td></tr></tbody></table><p>它们的共同点是<strong>判定/产出与代码解耦</strong>:</p><ul><li><strong>谓词可复用、可组合</strong>:一个 <code>is_in_rain</code> 谓词,既能被 <code>execute if predicate</code> 当命令条件,又能被战利品表当掉落条件,还能被选择器引用。写一次,处处复用。</li><li><strong>战利品表是&quot;掉落&quot;的唯一真相</strong>:回到第 9 篇讲过的——地牢箱子不预存物品,只存 <code>LootTable</code> 引用 + 种子,首次打开时按这张表现算。怪物掉什么、钓上来什么,全是战利品表。改掉落不改代码,改 JSON。</li><li><strong>进度常被当&quot;事件系统&quot;用</strong>:它的触发器(<code>minecraft:player_killed_entity</code>、<code>minecraft:inventory_changed</code>…)本质是&quot;当某事发生&quot;的钩子,地图作者用隐藏进度 + reward function 实现&quot;杀怪触发剧情&quot;这类事件逻辑——一个被玩出新用途的设计。</li></ul><hr><h2 id="五、把这一层放回全局" tabindex="-1">五、把这一层放回全局 <a class="header-anchor" href="#五、把这一层放回全局" aria-label="Permalink to &quot;五、把这一层放回全局&quot;">​</a></h2><p>退一步看,这一整层和前面的关系很清晰:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       指令 / mcfunction / 谓词 / 战利品表 / 进度 / 配方   ← 逻辑·脚本层(本篇,纯数据驱动)</span></span>
<span class="line"><span>                          ↑ 读写</span></span>
<span class="line"><span>       注册表 · 标签 · 动态注册表 · 数据包                  ← 第 11 篇:内容定义与元系统</span></span>
<span class="line"><span>                          ↑ 基于</span></span>
<span class="line"><span>       方块 · 实体 · 物品(组件)· NBT · 计分板 · 世界状态   ← 第 6/8/9/17 篇:数据模型</span></span>
<span class="line"><span>                          ↑ 跑在</span></span>
<span class="line"><span>       20 TPS Tick 循环(#minecraft:tick 把函数挂进来)     ← 第 4 篇</span></span></code></pre></div><p>几个值得记住的取舍与反直觉:</p><ul><li><strong>它不写 Java,却图灵完备到能做小游戏、剧情、自定义机制</strong>。代价是没有真正的变量和数据结构,一切靠计分板(整数)、NBT 存储、宏(macro,较新版本)硬凑——表达力换来了&quot;零编译、改完 <code>/reload</code> 就生效、可热分发&quot;。</li><li><strong>数据包和模组是两条路</strong>:模组改 Java 字节码、能加新方块新实体;数据包只能&quot;在现有积木上重组逻辑和数据&quot;。但数据包<strong>纯数据、跨版本相对稳、服务端单方面下发即可</strong>(呼应第 11 篇 registry/数据同步),所以原版地图、商业服玩法大量用它而不是模组。</li><li><strong>命令的成本是真实的</strong>。<code>@e</code> 扫表、<code>execute as</code> 展开、<code>#minecraft:tick</code> 的每秒 20 次,叠起来就是服务器 MSPT 的一部分。把这层当&quot;轻量脚本&quot;写没问题,但它和方块实体、实体一样,最终都汇进同一个 tick 预算。</li></ul><p>所以&quot;指令系统&quot;这个名字其实低估了它:它是 Minecraft 暴露给非程序员的、对整套世界数据模型的<strong>结构化读写与逻辑编排接口</strong>,也是这套数据模型设计得足够规整(注册表 ID、NBT、组件、标签)之后,自然能长出来的一层。</p>`,44)])])}const h=e(s,[["render",d]]);export{g as __pageData,h as default};
